code = """import json, re
fp = var_call_LbZM6NfM4hZBsPkYpIDJ4V0m
with open(fp, 'r', encoding='utf-8') as f:
    data = json.load(f)

cat_to_brefs = {}

pat = re.compile(r"(?:offers|offering|provides|providing|is a premier destination for|destination for|including|features)(.*?)(?:\.|$)", flags=re.IGNORECASE)

for b in data:
    attrs = b.get('attributes')
    if not (isinstance(attrs, dict) and attrs.get('BusinessAcceptsCreditCards') == 'True'):
        continue
    bid = b.get('business_id')
    if not bid:
        continue
    bref = bid.replace('businessid_', 'businessref_')
    # Try categories field first
    cats = b.get('categories')
    cat_list = []
    if cats:
        if isinstance(cats, list):
            cat_list = [c.strip() for c in cats if c]
        else:
            cat_list = [c.strip() for c in str(cats).split(',') if c.strip()]
    # If no categories, try description
    if not cat_list:
        desc = b.get('description') or ''
        if desc:
            m = pat.search(desc)
            if m:
                seg = m.group(1)
                # remove leading phrases like ' a wide range of services in '
                seg = re.sub(r"^\s*(a|the|this facility|this establishment|a wide range of services in|a range of services in|a wide range of services|a range of services)\s*", '', seg, flags=re.IGNORECASE)
                # split by common separators
                parts = re.split(r',| and | & |/|;|\|', seg)
                parts = [p.strip().strip('.') for p in parts if p.strip()]
                cat_list = parts
    # sanitize
    cat_list = [c for c in cat_list if len(c) > 1]
    if not cat_list:
        continue
    for c in cat_list:
        cat_to_brefs.setdefault(c, set()).add(bref)

counts = {c: len(s) for c, s in cat_to_brefs.items()}
if counts:
    top_category = sorted(counts.items(), key=lambda x: (-x[1], x[0]))[0][0]
    top_brefs = sorted(list(cat_to_brefs[top_category]))
    out = {'top_category': top_category, 'count': counts[top_category], 'business_refs': top_brefs}
else:
    out = {'top_category': None, 'count': 0, 'business_refs': []}

print('__RESULT__:')
print(json.dumps(out))"""

